INSERT INTO `recipes` (`id`, `title`, `preparation_time`, `servings`, `instructions`, `notes`, `description`, `recipe_status_id`, `created_by`, `created_at`, `active`, `approved_by`) VALUES
(1, 'Spaghetti Bolognese', 45, 4, '[{\"text\":\"Cook spaghetti in salted boiling water until al dente.\"},{\"text\":\"SautГ© onion and garlic in olive oil.\"},{\"text\":\"Add minced beef and brown\"},{\"text\":\"Stir in canned tomatoes and tomato paste. \"},{\"text\":\"Simmer 20 min.\"},{\"text\":\"Serve sauce over pasta.\"}]', 'For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.', 'A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.', 6, 3, '2026-06-15 09:45:18', NULL, 2),
(3, 'Spaghetti Bolognese', 50, 5, '[{\"text\":\"Cook spaghetti in salted boiling water until al dente.\"},{\"text\":\"Saute onion and garlic in olive oil.\"},{\"text\":\"Add minced beef and brown.\"},{\"text\":\"Stir in canned tomatoes and tomato paste.\"},{\"text\":\"Simmer 20 min.\"},{\"text\":\"Serve sauce over pasta.\"}]', 'For best results simmer the sauce for the full 50 minutes - the longer it cooks, the richer the flavor. Deglaze with a splash of red wine after browning the beef for extra depth.', 'A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.', 5, 3, '2026-06-18 14:22:05', 1, 2),
(4, 'Chicken Soup', 60, 8, '[{\"text\":\"Place chicken and vegetables in pot with broth.\"},{\"text\":\"Bring to boil, skim foam.\"},{\"text\":\"Simmer 40 min.\"},{\"text\":\"Remove chicken, shred meat, discard bones.\"},{\"text\":\"Return meat to soup, season and garnish with parsley.\"}]', NULL, 'A warming, golden broth with tender shredded chicken, plenty of carrots, and fresh parsley. Simple, nourishing, and perfect when you need something comforting.', 5, 2, '2026-03-14 10:30:44', 1, 2),
(5, 'Lentil Soup', 40, 6, '[{\"text\":\"Saute onion and garlic in olive oil.\"},{\"text\":\"Add lentils, canned tomatoes, cumin, paprika.\"},{\"text\":\"Cover with water.\"},{\"text\":\"Simmer 25 min until lentils are soft.\"},{\"text\":\"Taste and adjust seasoning, then serve.\"}]', 'No need to soak red lentils - they cook quickly. Rinse them well before using. Adjust salt at the end as canned tomatoes vary in saltiness.', 'A thick and earthy soup of red lentils, tomatoes, and aromatic cumin and paprika. Filling, budget-friendly, and naturally vegan.', 5, 3, '2026-06-05 11:20:33', 1, 5),
(6, 'Scrambled Eggs with Ham', 10, 2, '[{\"text\":\"Dice ham.\"},{\"text\":\"Whisk eggs with salt and pepper.\"},{\"text\":\"Melt butter in pan over medium heat.\"},{\"text\":\"Add ham and cook 1 min.\"},{\"text\":\"Pour in eggs and stir gently until just set.\"}]', NULL, 'Soft, buttery scrambled eggs cooked with diced ham. A quick and protein-packed breakfast that comes together in minutes.', 5, 3, '2026-04-19 08:15:27', 1, 5),
(7, 'Garlic Butter Shrimp', 20, 6, '[{\"text\":\"Melt butter in pan over medium heat.\"},{\"text\":\"Add garlic and cook 1 min.\"},{\"text\":\"Add shrimp and cook 2 min per side.\"},{\"text\":\"Squeeze lemon juice and toss with fresh parsley.\"}]', 'Do not overcook the shrimp - they turn rubbery quickly. Pull them off the heat the moment they turn pink and curl into a C-shape.', 'Juicy shrimp pan-fried in fragrant garlic butter and finished with a squeeze of lemon. Ready in 20 minutes and impressive enough to serve as a starter.', 5, 3, '2026-06-01 09:30:12', 1, 5),
(8, 'Rice Pilaf', 25, 4, '[{\"text\":\"Saute onion in butter until soft.\"},{\"text\":\"Add garlic and rice, stir 1 min.\"},{\"text\":\"Pour in broth.\"},{\"text\":\"Cover and cook on low heat 18 min.\"},{\"text\":\"Fluff with fork and season.\"}]', NULL, 'Fluffy long-grain rice toasted in butter and cooked in chicken broth with onion and garlic. An effortless side dish that pairs with almost anything.', 5, 2, '2026-03-18 14:45:38', 1, 2),
(9, 'Pork Tenderloin with Mushroom Cream Sauce', 40, 4, '[{\"text\":\"Slice pork and season.\"},{\"text\":\"Sear in butter until golden, set aside.\"},{\"text\":\"Saute onion and garlic in same pan.\"},{\"text\":\"Add mushrooms, cook until soft.\"},{\"text\":\"Deglaze with wine.\"},{\"text\":\"Add cream and simmer 5 min.\"},{\"text\":\"Return pork to pan and heat through.\"}]', 'Pat the pork completely dry before searing for a proper golden crust. Avoid crowding the pan or the meat will steam instead of brown.', 'Seared pork slices in a velvety cream and white wine sauce with sauteed mushrooms. An elegant dinner that feels restaurant-quality.', 6, 4, '2026-06-16 14:30:55', NULL, 2),
(10, 'Cream of Tomato Soup', 30, 4, '[{\"text\":\"Saute onion and garlic in oil.\"},{\"text\":\"Add canned tomatoes and oregano.\"},{\"text\":\"Simmer 15 min.\"},{\"text\":\"Blend until smooth.\"},{\"text\":\"Stir in cream and season.\"}]', NULL, 'Blended canned tomatoes and aromatics finished with cream for a smooth, comforting soup. Rich, slightly tangy, and deeply satisfying.', 5, 3, '2026-04-24 10:15:44', 1, 5),
(11, 'Baked Salmon with Dill', 25, 6, '[{\"text\":\"Preheat oven to 200C.\"},{\"text\":\"Place salmon on a lined baking sheet.\"},{\"text\":\"Rub with olive oil and minced garlic.\"},{\"text\":\"Season with salt and pepper, squeeze lemon over.\"},{\"text\":\"Bake 15 min on the middle rack.\"},{\"text\":\"Rest 3 min, then garnish with fresh dill and serve.\"}]', 'Middle oven rack is key for even cooking. The salmon is done when it flakes easily with a fork at the thickest part. Rest 3 minutes before serving for best texture.', 'Oven-roasted salmon fillet seasoned with garlic, olive oil, and fresh dill with a generous squeeze of lemon. Light, healthy, and ready in under 25 minutes.', 5, 4, '2026-05-20 11:00:22', 1, 2),
(12, 'Fried Rice with Egg', 20, 4, '[{\"text\":\"Cook rice and let cool.\"},{\"text\":\"Heat oil in pan over high heat.\"},{\"text\":\"Saute garlic and onion.\"},{\"text\":\"Push aside and scramble eggs.\"},{\"text\":\"Add rice and corn.\"},{\"text\":\"Pour in soy sauce and toss together.\"}]', NULL, 'Leftover rice stir-fried over high heat with egg, corn, onion, and soy sauce. A great weeknight staple that uses up what\'s in the fridge.', 5, 5, '2026-03-27 13:20:49', 1, 5),
(13, 'Mushroom Risotto', 40, 4, '[{\"text\":\"Saute onion and garlic in butter over medium heat.\"},{\"text\":\"Add mushrooms and cook until soft and golden.\"},{\"text\":\"Add rice and stir 1 min to toast lightly.\"},{\"text\":\"Deglaze with wine and stir until absorbed.\"},{\"text\":\"Add broth one ladle at a time over medium-low heat, waiting until each ladle is fully absorbed before adding the next.\"},{\"text\":\"Finish with grated cheese, adjust seasoning, and serve immediately.\"}]', 'Keep the broth warm in a separate pot while cooking - adding cold broth stops the cooking process and results in uneven texture. Stir constantly during the final 10 minutes.', 'Creamy Arborio-style rice slowly cooked with mushrooms, white wine, and chicken broth, finished with grated kashkaval. Rich and deeply savory.', 5, 3, '2026-04-05 16:45:11', 1, 2),
(14, 'Stuffed Peppers', 55, 6, '[{\"text\":\"Cut tops off peppers and remove seeds.\"},{\"text\":\"Saute onion and garlic, add minced beef and brown.\"},{\"text\":\"Stir in rice, paprika, salt and pepper.\"},{\"text\":\"Fill peppers with mixture.\"},{\"text\":\"Place in baking dish with tomato puree.\"},{\"text\":\"Bake at 180C for 40 min.\"}]', NULL, 'Whole peppers filled with spiced minced beef and rice, baked in tomato puree until tender. A comforting, all-in-one family meal.', 5, 2, '2026-03-22 09:45:33', 1, 2),
(15, 'Honey Garlic Chicken', 25, 4, '[{\"text\":\"Slice chicken fillets into strips.\"},{\"text\":\"Mix honey, soy sauce, and minced garlic.\"},{\"text\":\"Heat oil in pan.\"},{\"text\":\"Cook chicken until golden on all sides.\"},{\"text\":\"Pour honey sauce over and cook 2 min until glazed.\"}]', NULL, 'Chicken fillets glazed in a sweet and savory sauce of honey, soy sauce, and garlic. Sticky, golden, and ready in under 30 minutes.', 5, 3, '2026-06-07 14:15:08', 1, 2),
(16, 'Spinach and Egg Frittata', 30, 6, '[{\"text\":\"Preheat oven to 180C.\"},{\"text\":\"Saute onion in oil until soft.\"},{\"text\":\"Add spinach and cook until wilted.\"},{\"text\":\"Whisk eggs, add salt and pepper.\"},{\"text\":\"Pour eggs over vegetables in oven-safe pan.\"},{\"text\":\"Top with grated cheese.\"},{\"text\":\"Bake 20 min until set.\"},{\"text\":\"Scatter fresh parsley over before serving.\"}]', NULL, 'A baked egg frittata with wilted spinach, onion, and grated kashkaval, finished with fresh parsley. Serve warm from the pan as a light lunch or protein-packed breakfast.', 5, 4, '2026-05-15 14:45:22', 1, 5),
(17, 'Chocolate Mousse', 20, 6, '[{\"text\":\"Melt chocolate.\"},{\"text\":\"Separate eggs; whisk yolks with sugar until pale.\"},{\"text\":\"Fold in melted chocolate and vanilla.\"},{\"text\":\"Whip cream to soft peaks.\"},{\"text\":\"Beat egg whites to stiff peaks.\"},{\"text\":\"Fold cream then whites into chocolate mixture.\"},{\"text\":\"Refrigerate 2 hours.\"}]', 'Use the best quality dark chocolate available - it is the main flavor. Make sure no yolk gets into the egg whites or they will not whip to stiff peaks.', 'An airy, indulgent dessert of dark chocolate folded with whipped cream and beaten egg whites. Light yet intensely chocolatey.', 5, 4, '2026-04-11 11:30:44', 1, 2),
(18, 'Chickpea Stew', 35, 4, '[{\"text\":\"Saute onion and garlic in oil.\"},{\"text\":\"Add paprika and cumin, stir 30 sec.\"},{\"text\":\"Add chickpeas and canned tomatoes.\"},{\"text\":\"Simmer 20 min.\"},{\"text\":\"Season with salt and top with parsley.\"}]', NULL, 'A rustic stew of tender chickpeas simmered in spiced tomato sauce with cumin and paprika. Hearty, plant-based comfort food.', 5, 3, '2026-04-28 15:40:17', 1, 5),
(19, 'Beef and Potato Stew', 90, 6, '[{\"text\":\"Brown minced beef in pot.\"},{\"text\":\"Add onion and garlic, cook 2 min.\"},{\"text\":\"Stir in tomato paste and paprika.\"},{\"text\":\"Add broth, potatoes, and carrots.\"},{\"text\":\"Simmer 60 min.\"},{\"text\":\"Season and serve.\"}]', 'Cut the potatoes into large chunks so they hold their shape during the long simmer. If the stew gets too thick, add a splash of broth to loosen it.', 'A robust, slow-cooked stew of minced beef, potatoes, and carrots in a paprika-spiced beef broth. Perfect for cold days.', 5, 4, '2026-04-15 16:00:38', 1, 2),
(20, 'Tomato and Onion Salad', 10, 4, '[{\"text\":\"Slice tomatoes and onion into thin rings.\"},{\"text\":\"Arrange on plate.\"},{\"text\":\"Drizzle with olive oil.\"},{\"text\":\"Season with salt, pepper, and oregano.\"},{\"text\":\"Garnish with fresh parsley.\"}]', NULL, 'Thinly sliced tomatoes and onions dressed with olive oil, oregano, and fresh parsley. A simple Mediterranean side that lets the ingredients speak for themselves.', 5, 4, '2026-05-11 10:30:55', 1, 5),
(21, 'Chocolate Cake', 55, 10, '[{\"text\":\"Preheat oven to 175C.\"},{\"text\":\"Cream butter and sugar until fluffy.\"},{\"text\":\"Beat in eggs and vanilla.\"},{\"text\":\"Mix in flour, cocoa, and salt alternating with milk.\"},{\"text\":\"Pour into greased pan.\"},{\"text\":\"Bake 35 min until skewer comes out clean.\"}]', 'Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.', 'A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.', 5, 4, '2026-05-02 14:20:11', 1, 5),
(22, 'Yogurt with Honey and Walnuts', 5, 2, '[{\"text\":\"Spoon yogurt into bowls.\"},{\"text\":\"Roughly chop walnuts.\"},{\"text\":\"Top yogurt with walnuts.\"},{\"text\":\"Drizzle honey over.\"}]', NULL, 'Thick creamy yogurt topped with crunchy walnuts and a generous drizzle of honey. A simple, nutritious breakfast or light dessert.', 5, 4, '2026-05-06 08:50:27', 1, 5),
(23, 'Apple and Walnut Salad', 10, 4, '[{\"text\":\"Core and slice apples, toss immediately with lemon juice to prevent browning.\"},{\"text\":\"Mix honey into yogurt to make dressing.\"},{\"text\":\"Roughly chop walnuts.\"},{\"text\":\"Combine apples and walnuts, drizzle with yogurt dressing.\"}]', NULL, 'Crisp sliced apples and chopped walnuts tossed with a honey-yogurt dressing and a splash of lemon. Fresh, crunchy, and naturally sweet.', 5, 5, '2026-04-01 15:40:44', 1, 5),
(24, 'Shrimp Pasta', 30, 4, '[{\"text\":\"Cook pasta in salted water until al dente.\"},{\"text\":\"Saute garlic in olive oil until golden.\"},{\"text\":\"Add shrimp and cook 3 min.\"},{\"text\":\"Toss with drained pasta.\"},{\"text\":\"Finish with lemon juice and chopped parsley.\"}]', 'Reserve a cup of pasta water before draining. Adding a splash while tossing the pasta with the shrimp helps the sauce cling and keeps everything from drying out.', 'Spaghetti tossed with pan-fried shrimp in garlic olive oil, brightened with fresh lemon juice and parsley. A quick and elegant seafood dinner.', 5, 3, '2026-06-11 13:00:28', 1, 2),
(25, 'Baked Chicken Legs with Potatoes', 60, 4, '[{\"text\":\"Preheat oven to 200C.\"},{\"text\":\"Cut potatoes into wedges.\"},{\"text\":\"Toss chicken legs and potatoes with oil, minced garlic, paprika, oregano, salt, pepper.\"},{\"text\":\"Arrange in single layer in baking dish.\"},{\"text\":\"Roast 45 min until skin is golden.\"}]', 'For extra crispy skin, pat the chicken dry and leave it uncovered in the fridge for an hour before seasoning. Avoid covering the dish during roasting.', 'Chicken legs and potato wedges roasted together with garlic, paprika, and oregano until golden and crispy. A simple one-pan dinner with minimal effort.', 5, 4, '2026-05-28 15:30:51', 1, 2),
(26, 'Tomato and Pepper Sauce', 25, 8, '[{\"text\":\"Saute onion, garlic, and diced peppers in oil over medium heat.\"},{\"text\":\"Add canned tomatoes and oregano.\"},{\"text\":\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\"},{\"text\":\"Blend for smooth texture or leave chunky.\"},{\"text\":\"Stir in chopped parsley, season to taste, and use on pasta, pizza, or as dipping sauce.\"}]', 'The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.', 'A chunky tomato and pepper sauce with garlic, oregano, and fresh parsley, ready in just 25 minutes. Versatile as a pasta sauce, pizza base, or dipping sauce.', 6, 4, '2026-06-17 10:00:33', NULL, 5),
(27, 'Bacon and Egg Potato Hash', 30, 4, '[{\"text\":\"Dice potatoes and parboil 10 min, then drain and pat dry.\"},{\"text\":\"Fry Bakone in pan until crispy, set aside.\"},{\"text\":\"Saute onion and garlic in remaining fat, add oil if needed.\"},{\"text\":\"Add potatoes and fry over medium-high heat until golden and crispy, about 8 min.\"},{\"text\":\"Reduce to medium-low, make 4 wells and crack in eggs.\"},{\"text\":\"Cover and cook 3-4 min until whites are fully set but yolks are still runny.\"},{\"text\":\"Top with Bakone and parsley and serve immediately.\"}]', NULL, 'Crispy diced potatoes fried with Bakone and topped with eggs cooked right in the pan. A satisfying, all-in-one breakfast skillet.', 5, 4, '2026-06-09 10:45:16', 1, 2),
(28, 'Buttered Pasta', 15, 2, '[{\"text\":\"Cook pasta in salted water.\"},{\"text\":\"Drain and toss with butter and salt.\"}]', NULL, 'Simple pasta tossed with butter and salt. A quick comfort dish.', 4, 3, '2026-06-21 09:30:42', NULL, NULL),
(29, 'Vegetable Broth Soup', 20, 4, '[{\"text\":\"Bring broth to boil.\"},{\"text\":\"Add vegetables and simmer 15 min.\"},{\"text\":\"Season and serve.\"}]', NULL, 'A light, clear vegetable broth soup with carrots and onion.', 4, 4, '2026-06-22 14:15:07', NULL, NULL),
(31, 'Sauteed Garlic Mushrooms', 10, 2, '[{\"text\":\"Slice mushrooms.\"},{\"text\":\"Melt butter in pan, add garlic.\"},{\"text\":\"Add mushrooms and cook 5 min until golden.\"}]', NULL, 'Mushrooms quickly sauteed in butter with garlic. A simple side or topping.', 4, 4, '2026-06-23 11:00:19', NULL, NULL),
(32, 'Vegan Date and Cashew protein balls', NULL, NULL, '[{\"text\":\"Put the dates and the cashew in a blender\"}]', NULL, NULL, 1, 2, '2026-06-25 18:30:44', NULL, NULL),
(33, 'Cheesecake', 30, 15, NULL, NULL, NULL, 3, 3, '2026-06-25 20:15:33', NULL, NULL);
