INSERT INTO `recipe_review_logs` (`id`, `recipe_id`, `reviewer_id`, `snapshot`, `return_notes`, `recipe_review_event_id`, `created_at`) VALUES
(1, 1, 2, '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"SautГ© onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste. \\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"mg\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', NULL, 1, '2026-06-15 16:30:00'),
(2, 1, 2, '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"SautГ© onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste. \\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"mg\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', NULL, 4, '2026-06-16 10:15:00'),
(3, 4, 2, '{\"title\":\"Chicken Soup\",\"preparationTime\":60,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Place chicken and vegetables in pot with broth.\\\"},{\\\"text\\\":\\\"Bring to boil, skim foam.\\\"},{\\\"text\\\":\\\"Simmer 40 min.\\\"},{\\\"text\\\":\\\"Remove chicken, shred meat, discard bones.\\\"},{\\\"text\\\":\\\"Return meat to soup, season and garnish with parsley.\\\"}]\",\"notes\":null,\"description\":\"A warming, golden broth with tender shredded chicken, carrots, and fresh parsley. Simple, nourishing, and perfect for any season.\",\"products\":[{\"productName\":\"Chicken leg\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Carrots\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Chicken broth\",\"position\":5,\"quantity\":1500.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":8,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Poultry\"},{\"category\":\"Soups & Stews\"}]}', NULL, 4, '2026-03-15 10:30:00'),
(4, 8, 2, '{\"title\":\"Rice Pilaf\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion in butter until soft.\\\"},{\\\"text\\\":\\\"Add garlic and rice, stir 1 min.\\\"},{\\\"text\\\":\\\"Pour in broth.\\\"},{\\\"text\\\":\\\"Cover and cook on low heat 18 min.\\\"},{\\\"text\\\":\\\"Fluff with fork and season.\\\"}]\",\"notes\":null,\"description\":\"Fluffy long-grain rice toasted in butter and cooked in chicken broth with onion and garlic. An effortless side dish that pairs with almost anything.\",\"products\":[{\"productName\":\"Rice\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Chicken broth\",\"position\":4,\"quantity\":600.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":2.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Side Dishes\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-03-19 14:15:00'),
(5, 14, 2, '{\"title\":\"Stuffed Peppers\",\"preparationTime\":55,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cut tops off peppers and remove seeds.\\\"},{\\\"text\\\":\\\"Saute onion and garlic, add minced beef and brown.\\\"},{\\\"text\\\":\\\"Stir in rice, paprika, salt and pepper.\\\"},{\\\"text\\\":\\\"Fill peppers with mixture.\\\"},{\\\"text\\\":\\\"Place in baking dish with tomato puree.\\\"},{\\\"text\\\":\\\"Bake at 180C for 40 min.\\\"}]\",\"notes\":null,\"description\":\"Whole peppers filled with spiced minced beef and rice, baked in tomato puree until tender. A comforting, all-in-one family meal.\",\"products\":[{\"productName\":\"Peppers\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Rice\",\"position\":3,\"quantity\":100.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato puree\",\"position\":4,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Paprika\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Main Dishes\"}]}', NULL, 4, '2026-03-23 11:45:00'),
(6, 12, 5, '{\"title\":\"Fried Rice with Egg\",\"preparationTime\":20,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook rice and let cool.\\\"},{\\\"text\\\":\\\"Heat oil in pan over high heat.\\\"},{\\\"text\\\":\\\"Saute garlic and onion.\\\"},{\\\"text\\\":\\\"Push aside and scramble eggs.\\\"},{\\\"text\\\":\\\"Add rice and corn.\\\"},{\\\"text\\\":\\\"Pour in soy sauce and toss together.\\\"}]\",\"notes\":null,\"description\":\"Leftover rice stir-fried over high heat with egg, corn, onion, and soy sauce. A great weeknight staple that uses up what\'s in the fridge.\",\"products\":[{\"productName\":\"Rice\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":2,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Soy sauce\",\"position\":5,\"quantity\":45.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Sunflower oil\",\"position\":6,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Canned corn\",\"position\":7,\"quantity\":100.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Side Dishes\"}]}', NULL, 4, '2026-03-28 09:20:00'),
(7, 23, 5, '{\"title\":\"Apple and Walnut Salad\",\"preparationTime\":10,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Core and slice apples, toss immediately with lemon juice to prevent browning.\\\"},{\\\"text\\\":\\\"Mix honey into yogurt to make dressing.\\\"},{\\\"text\\\":\\\"Roughly chop walnuts.\\\"},{\\\"text\\\":\\\"Combine apples and walnuts, drizzle with yogurt dressing.\\\"}]\",\"notes\":null,\"description\":\"Crisp sliced apples and chopped walnuts tossed with a honey-yogurt dressing and a splash of lemon. Fresh, crunchy, and naturally sweet.\",\"products\":[{\"productName\":\"Apples\",\"position\":1,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Walnuts\",\"position\":2,\"quantity\":80.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Yogurt\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Honey\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Salads\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-04-02 15:40:00'),
(8, 3, 2, '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown.\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', NULL, 1, '2026-06-18 16:00:00'),
(9, 15, 2, '{\"title\":\"Honey Garlic Chicken\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice chicken fillets into strips.\\\"},{\\\"text\\\":\\\"Mix honey, soy sauce, and minced garlic.\\\"},{\\\"text\\\":\\\"Heat oil in pan.\\\"},{\\\"text\\\":\\\"Cook chicken until golden on all sides.\\\"},{\\\"text\\\":\\\"Pour honey sauce over and cook 2 min until glazed.\\\"}]\",\"notes\":null,\"description\":\"Chicken fillets glazed in a sweet and savory sauce of honey, soy sauce, and garlic. Sticky, golden, and ready in under 30 minutes.\",\"products\":[{\"productName\":\"Chicken fillet\",\"position\":1,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Honey\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Soy sauce\",\"position\":3,\"quantity\":60.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Sunflower oil\",\"position\":5,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Poultry\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 1, '2026-06-07 15:30:00'),
(10, 24, 2, '{\"title\":\"Shrimp Pasta\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook pasta in salted water until al dente.\\\"},{\\\"text\\\":\\\"Saute garlic in olive oil until golden.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 3 min.\\\"},{\\\"text\\\":\\\"Toss with drained pasta.\\\"},{\\\"text\\\":\\\"Finish with lemon juice and chopped parsley.\\\"}]\",\"notes\":\"Reserve a cup of pasta water before draining. Adding a splash while tossing the pasta with the shrimp helps the sauce cling and keeps everything from drying out.\",\"description\":\"Spaghetti tossed with pan-fried shrimp in garlic olive oil, brightened with fresh lemon juice and parsley. A quick and elegant seafood dinner.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Shrimp\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":45.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Pasta & Noodles\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', NULL, 1, '2026-06-11 16:00:00'),
(11, 6, 5, '{\"title\":\"Scrambled Eggs with Ham\",\"preparationTime\":10,\"servings\":2,\"instructions\":\"[{\\\"text\\\":\\\"Dice ham.\\\"},{\\\"text\\\":\\\"Whisk eggs with salt and pepper.\\\"},{\\\"text\\\":\\\"Melt butter in pan over medium heat.\\\"},{\\\"text\\\":\\\"Add ham and cook 1 min.\\\"},{\\\"text\\\":\\\"Pour in eggs and stir gently until just set.\\\"}]\",\"notes\":null,\"description\":\"Soft, buttery scrambled eggs cooked with diced ham. A quick and protein-packed breakfast that comes together in minutes.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Ham\",\"position\":2,\"quantity\":80.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Butter\",\"position\":3,\"quantity\":15.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 1, '2026-04-19 15:45:00'),
(12, 7, 5, '{\"title\":\"Garlic Butter Shrimp\",\"preparationTime\":15,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Melt butter in pan over medium heat.\\\"},{\\\"text\\\":\\\"Add garlic and cook 1 min.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 2 min per side.\\\"},{\\\"text\\\":\\\"Squeeze lemon juice and toss with fresh parsley.\\\"}]\",\"notes\":\"Do not overcook the shrimp - they turn rubbery quickly. Pull them off the heat the moment they turn pink and curl into a C-shape.\",\"description\":\"Juicy shrimp pan-fried in fragrant garlic butter and finished with a squeeze of lemon. Ready in 15 minutes and impressive enough to serve as a starter.\",\"products\":[{\"productName\":\"Shrimp\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Butter\",\"position\":2,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Lemons\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', NULL, 1, '2026-06-01 16:00:00'),
(13, 10, 5, '{\"title\":\"Cream of Tomato Soup\",\"preparationTime\":30,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in oil.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 15 min.\\\"},{\\\"text\\\":\\\"Blend until smooth.\\\"},{\\\"text\\\":\\\"Stir in cream and season.\\\"}]\",\"notes\":null,\"description\":\"Blended canned tomatoes and aromatics finished with cream for a smooth, comforting soup. Rich, slightly tangy, and deeply satisfying.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Heavy cream 35%\",\"position\":5,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-04-24 15:00:00'),
(14, 18, 5, '{\"title\":\"Chickpea Stew\",\"preparationTime\":35,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in oil.\\\"},{\\\"text\\\":\\\"Add paprika and cumin, stir 30 sec.\\\"},{\\\"text\\\":\\\"Add chickpeas and canned tomatoes.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Season with salt and top with parsley.\\\"}]\",\"notes\":null,\"description\":\"A rustic stew of tender chickpeas simmered in spiced tomato sauce with cumin and paprika. Hearty, plant-based comfort food.\",\"products\":[{\"productName\":\"Chickpeas\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Paprika\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-04-28 16:30:00'),
(15, 9, 2, '{\"title\":\"Pork Tenderloin with Mushroom Cream Sauce\",\"preparationTime\":35,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice pork and season.\\\"},{\\\"text\\\":\\\"Sear in butter until golden, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in same pan.\\\"},{\\\"text\\\":\\\"Add mushrooms, cook until soft.\\\"},{\\\"text\\\":\\\"Deglaze with wine.\\\"},{\\\"text\\\":\\\"Add cream and simmer 5 min.\\\"},{\\\"text\\\":\\\"Return pork to pan and heat through.\\\"}]\",\"notes\":\"Pat the pork completely dry before searing for a proper golden crust. Avoid crowding the pan or the meat will steam instead of brown.\",\"description\":\"Seared pork slices in a velvety cream and white wine sauce with sauteed mushrooms. An elegant dinner that feels restaurant-quality.\",\"products\":[{\"productName\":\"Pork tenderloin\",\"position\":1,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Mushrooms\",\"position\":2,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Heavy cream 35%\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"White wine (for cooking)\",\"position\":4,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Main Dishes\"}]}', NULL, 1, '2026-06-16 17:00:00'),
(16, 17, 2, '{\"title\":\"Chocolate Mousse\",\"preparationTime\":20,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Melt chocolate.\\\"},{\\\"text\\\":\\\"Separate eggs; whisk yolks with sugar until pale.\\\"},{\\\"text\\\":\\\"Fold in melted chocolate and vanilla.\\\"},{\\\"text\\\":\\\"Whip cream to soft peaks.\\\"},{\\\"text\\\":\\\"Beat egg whites to stiff peaks.\\\"},{\\\"text\\\":\\\"Fold cream then whites into chocolate mixture.\\\"},{\\\"text\\\":\\\"Refrigerate 2 hours.\\\"}]\",\"notes\":\"Use the best quality dark chocolate available - it is the main flavor. Make sure no yolk gets into the egg whites or they will not whip to stiff peaks.\",\"description\":\"An airy, indulgent dessert of dark chocolate folded with whipped cream and beaten egg whites. Light yet intensely chocolatey.\",\"products\":[{\"productName\":\"Dark chocolate 70%\",\"position\":1,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":2,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Heavy cream 35%\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"White sugar\",\"position\":4,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Vanilla (extract)\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"}],\"categories\":[{\"category\":\"Desserts\"}]}', NULL, 1, '2026-04-11 16:30:00'),
(17, 19, 2, '{\"title\":\"Beef and Potato Stew\",\"preparationTime\":90,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Brown minced beef in pot.\\\"},{\\\"text\\\":\\\"Add onion and garlic, cook 2 min.\\\"},{\\\"text\\\":\\\"Stir in tomato paste and paprika.\\\"},{\\\"text\\\":\\\"Add broth, potatoes, and carrots.\\\"},{\\\"text\\\":\\\"Simmer 60 min.\\\"},{\\\"text\\\":\\\"Season and serve.\\\"}]\",\"notes\":\"Cut the potatoes into large chunks so they hold their shape during the long simmer. If the stew gets too thick, add a splash of broth to loosen it.\",\"description\":\"A robust, slow-cooked stew of minced beef, potatoes, and carrots in a paprika-spiced beef broth. Perfect for cold days.\",\"products\":[{\"productName\":\"Minced beef\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Potatoes\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Carrots\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Beef broth\",\"position\":4,\"quantity\":500.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Tomato paste\",\"position\":5,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Paprika\",\"position\":8,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":9,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":10,\"quantity\":4.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Soups & Stews\"}]}', NULL, 1, '2026-04-15 17:00:00'),
(18, 25, 2, '{\"title\":\"Baked Chicken Legs with Potatoes\",\"preparationTime\":60,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Cut potatoes into wedges.\\\"},{\\\"text\\\":\\\"Toss chicken legs and potatoes with oil, minced garlic, paprika, oregano, salt, pepper.\\\"},{\\\"text\\\":\\\"Arrange in single layer in baking dish.\\\"},{\\\"text\\\":\\\"Roast 45 min until skin is golden.\\\"}]\",\"notes\":\"For extra crispy skin, pat the chicken dry and leave it uncovered in the fridge for an hour before seasoning. Avoid covering the dish during roasting.\",\"description\":\"Chicken legs and potato wedges roasted together with garlic, paprika, and oregano until golden and crispy. A simple one-pan dinner with minimal effort.\",\"products\":[{\"productName\":\"Chicken leg\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Potatoes\",\"position\":2,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":45.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Paprika\",\"position\":5,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Poultry\"}]}', NULL, 1, '2026-05-28 16:30:00'),
(19, 16, 5, '{\"title\":\"Spinach and Egg Frittata\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 180C.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in butter in an oven-safe pan.\\\"},{\\\"text\\\":\\\"Add spinach and cook until wilted.\\\"},{\\\"text\\\":\\\"Whisk eggs with salt and pepper, pour over.\\\"},{\\\"text\\\":\\\"Sprinkle grated cheese.\\\"},{\\\"text\\\":\\\"Bake 15 min until set.\\\"}]\",\"notes\":\"Make sure the spinach is fully wilted and any excess moisture is pressed out before adding the eggs, otherwise the frittata will be watery and won\'t set properly.\",\"description\":\"A baked egg dish loaded with wilted spinach and melted kashkaval cheese. A versatile, protein-rich option for breakfast or a light lunch.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":6.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Spinach\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":3,\"quantity\":80.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":6,\"quantity\":20.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-05-15 17:00:00'),
(20, 20, 5, '{\"title\":\"Tomato and Onion Salad\",\"preparationTime\":10,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice tomatoes and onion into thin rings.\\\"},{\\\"text\\\":\\\"Arrange on plate.\\\"},{\\\"text\\\":\\\"Drizzle with olive oil.\\\"},{\\\"text\\\":\\\"Season with salt, pepper, and oregano.\\\"},{\\\"text\\\":\\\"Garnish with fresh parsley.\\\"}]\",\"notes\":null,\"description\":\"Thinly sliced tomatoes and onions dressed with olive oil, oregano, and fresh parsley. A simple Mediterranean side that lets the ingredients speak for themselves.\",\"products\":[{\"productName\":\"Tomatoes\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":3,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":5,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":7,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Salads\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-05-11 15:00:00'),
(21, 21, 5, '{\"title\":\"Chocolate Cake\",\"preparationTime\":50,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":180.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', NULL, 1, '2026-05-02 17:00:00'),
(22, 22, 5, '{\"title\":\"Yogurt with Honey and Walnuts\",\"preparationTime\":5,\"servings\":2,\"instructions\":\"[{\\\"text\\\":\\\"Spoon yogurt into bowls.\\\"},{\\\"text\\\":\\\"Roughly chop walnuts.\\\"},{\\\"text\\\":\\\"Top yogurt with walnuts.\\\"},{\\\"text\\\":\\\"Drizzle honey over.\\\"}]\",\"notes\":null,\"description\":\"Thick creamy yogurt topped with crunchy walnuts and a generous drizzle of honey. A simple, nutritious breakfast or light dessert.\",\"products\":[{\"productName\":\"Yogurt\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Honey\",\"position\":2,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Walnuts\",\"position\":3,\"quantity\":60.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 1, '2026-05-06 15:30:00'),
(23, 3, 2, '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown.\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', NULL, 4, '2026-06-19 10:15:00'),
