(25, 15, 2, '{\"title\":\"Honey Garlic Chicken\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice chicken fillets into strips.\\\"},{\\\"text\\\":\\\"Mix honey, soy sauce, and minced garlic.\\\"},{\\\"text\\\":\\\"Heat oil in pan.\\\"},{\\\"text\\\":\\\"Cook chicken until golden on all sides.\\\"},{\\\"text\\\":\\\"Pour honey sauce over and cook 2 min until glazed.\\\"}]\",\"notes\":null,\"description\":\"Chicken fillets glazed in a sweet and savory sauce of honey, soy sauce, and garlic. Sticky, golden, and ready in under 30 minutes.\",\"products\":[{\"productName\":\"Chicken fillet\",\"position\":1,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Honey\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Soy sauce\",\"position\":3,\"quantity\":60.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Sunflower oil\",\"position\":5,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Poultry\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 4, '2026-06-08 10:30:00'),
