(27, 19, 2, '{\"title\":\"Beef and Potato Stew\",\"preparationTime\":90,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Brown minced beef in pot.\\\"},{\\\"text\\\":\\\"Add onion and garlic, cook 2 min.\\\"},{\\\"text\\\":\\\"Stir in tomato paste and paprika.\\\"},{\\\"text\\\":\\\"Add broth, potatoes, and carrots.\\\"},{\\\"text\\\":\\\"Simmer 60 min.\\\"},{\\\"text\\\":\\\"Season and serve.\\\"}]\",\"notes\":\"Cut the potatoes into large chunks so they hold their shape during the long simmer. If the stew gets too thick, add a splash of broth to loosen it.\",\"description\":\"A robust, slow-cooked stew of minced beef, potatoes, and carrots in a paprika-spiced beef broth. Perfect for cold days.\",\"products\":[{\"productName\":\"Minced beef\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Potatoes\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Carrots\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Beef broth\",\"position\":4,\"quantity\":500.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Tomato paste\",\"position\":5,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Paprika\",\"position\":8,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":9,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":10,\"quantity\":4.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Soups & Stews\"}]}', NULL, 4, '2026-04-16 11:15:00'),
(28, 24, 2, '{\"title\":\"Shrimp Pasta\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook pasta in salted water until al dente.\\\"},{\\\"text\\\":\\\"Saute garlic in olive oil until golden.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 3 min.\\\"},{\\\"text\\\":\\\"Toss with drained pasta.\\\"},{\\\"text\\\":\\\"Finish with lemon juice and chopped parsley.\\\"}]\",\"notes\":\"Reserve a cup of pasta water before draining. Adding a splash while tossing the pasta with the shrimp helps the sauce cling and keeps everything from drying out.\",\"description\":\"Spaghetti tossed with pan-fried shrimp in garlic olive oil, brightened with fresh lemon juice and parsley. A quick and elegant seafood dinner.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Shrimp\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":45.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Pasta & Noodles\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', NULL, 4, '2026-06-12 11:15:00'),
(29, 25, 2, '{\"title\":\"Baked Chicken Legs with Potatoes\",\"preparationTime\":60,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Cut potatoes into wedges.\\\"},{\\\"text\\\":\\\"Toss chicken legs and potatoes with oil, minced garlic, paprika, oregano, salt, pepper.\\\"},{\\\"text\\\":\\\"Arrange in single layer in baking dish.\\\"},{\\\"text\\\":\\\"Roast 45 min until skin is golden.\\\"}]\",\"notes\":\"For extra crispy skin, pat the chicken dry and leave it uncovered in the fridge for an hour before seasoning. Avoid covering the dish during roasting.\",\"description\":\"Chicken legs and potato wedges roasted together with garlic, paprika, and oregano until golden and crispy. A simple one-pan dinner with minimal effort.\",\"products\":[{\"productName\":\"Chicken leg\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Potatoes\",\"position\":2,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":45.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Paprika\",\"position\":5,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Poultry\"}]}', NULL, 4, '2026-05-29 10:30:00'),
(30, 6, 5, '{\"title\":\"Scrambled Eggs with Ham\",\"preparationTime\":10,\"servings\":2,\"instructions\":\"[{\\\"text\\\":\\\"Dice ham.\\\"},{\\\"text\\\":\\\"Whisk eggs with salt and pepper.\\\"},{\\\"text\\\":\\\"Melt butter in pan over medium heat.\\\"},{\\\"text\\\":\\\"Add ham and cook 1 min.\\\"},{\\\"text\\\":\\\"Pour in eggs and stir gently until just set.\\\"}]\",\"notes\":null,\"description\":\"Soft, buttery scrambled eggs cooked with diced ham. A quick and protein-packed breakfast that comes together in minutes.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Ham\",\"position\":2,\"quantity\":80.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Butter\",\"position\":3,\"quantity\":15.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 4, '2026-04-20 09:45:00'),
(31, 7, 5, '{\"title\":\"Garlic Butter Shrimp\",\"preparationTime\":15,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Melt butter in pan over medium heat.\\\"},{\\\"text\\\":\\\"Add garlic and cook 1 min.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 2 min per side.\\\"},{\\\"text\\\":\\\"Squeeze lemon juice and toss with fresh parsley.\\\"}]\",\"notes\":\"Do not overcook the shrimp - they turn rubbery quickly. Pull them off the heat the moment they turn pink and curl into a C-shape.\",\"description\":\"Juicy shrimp pan-fried in fragrant garlic butter and finished with a squeeze of lemon. Ready in 15 minutes and impressive enough to serve as a starter.\",\"products\":[{\"productName\":\"Shrimp\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Butter\",\"position\":2,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Lemons\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', NULL, 4, '2026-06-02 10:00:00'),
(32, 10, 5, '{\"title\":\"Cream of Tomato Soup\",\"preparationTime\":30,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in oil.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 15 min.\\\"},{\\\"text\\\":\\\"Blend until smooth.\\\"},{\\\"text\\\":\\\"Stir in cream and season.\\\"}]\",\"notes\":null,\"description\":\"Blended canned tomatoes and aromatics finished with cream for a smooth, comforting soup. Rich, slightly tangy, and deeply satisfying.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Heavy cream 35%\",\"position\":5,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-04-25 10:00:00');
INSERT INTO `recipe_review_logs` (`id`, `recipe_id`, `reviewer_id`, `snapshot`, `return_notes`, `recipe_review_event_id`, `created_at`) VALUES
(33, 16, 5, '{\"title\":\"Spinach and Egg Frittata\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 180C.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in butter in an oven-safe pan.\\\"},{\\\"text\\\":\\\"Add spinach and cook until wilted.\\\"},{\\\"text\\\":\\\"Whisk eggs with salt and pepper, pour over.\\\"},{\\\"text\\\":\\\"Sprinkle grated cheese.\\\"},{\\\"text\\\":\\\"Bake 15 min until set.\\\"}]\",\"notes\":\"Make sure the spinach is fully wilted and any excess moisture is pressed out before adding the eggs, otherwise the frittata will be watery and won\'t set properly.\",\"description\":\"A baked egg dish loaded with wilted spinach and melted kashkaval cheese. A versatile, protein-rich option for breakfast or a light lunch.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":6.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Spinach\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":3,\"quantity\":80.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":6,\"quantity\":20.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-05-16 11:00:00'),
(34, 18, 5, '{\"title\":\"Chickpea Stew\",\"preparationTime\":35,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in oil.\\\"},{\\\"text\\\":\\\"Add paprika and cumin, stir 30 sec.\\\"},{\\\"text\\\":\\\"Add chickpeas and canned tomatoes.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Season with salt and top with parsley.\\\"}]\",\"notes\":null,\"description\":\"A rustic stew of tender chickpeas simmered in spiced tomato sauce with cumin and paprika. Hearty, plant-based comfort food.\",\"products\":[{\"productName\":\"Chickpeas\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Paprika\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-04-29 11:20:00'),
(35, 20, 5, '{\"title\":\"Tomato and Onion Salad\",\"preparationTime\":10,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice tomatoes and onion into thin rings.\\\"},{\\\"text\\\":\\\"Arrange on plate.\\\"},{\\\"text\\\":\\\"Drizzle with olive oil.\\\"},{\\\"text\\\":\\\"Season with salt, pepper, and oregano.\\\"},{\\\"text\\\":\\\"Garnish with fresh parsley.\\\"}]\",\"notes\":null,\"description\":\"Thinly sliced tomatoes and onions dressed with olive oil, oregano, and fresh parsley. A simple Mediterranean side that lets the ingredients speak for themselves.\",\"products\":[{\"productName\":\"Tomatoes\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":3,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":5,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":7,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Salads\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-05-12 10:30:00'),
(36, 21, 5, '{\"title\":\"Chocolate Cake\",\"preparationTime\":50,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":180.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', NULL, 4, '2026-05-03 10:45:00'),
(37, 22, 5, '{\"title\":\"Yogurt with Honey and Walnuts\",\"preparationTime\":5,\"servings\":2,\"instructions\":\"[{\\\"text\\\":\\\"Spoon yogurt into bowls.\\\"},{\\\"text\\\":\\\"Roughly chop walnuts.\\\"},{\\\"text\\\":\\\"Top yogurt with walnuts.\\\"},{\\\"text\\\":\\\"Drizzle honey over.\\\"}]\",\"notes\":null,\"description\":\"Thick creamy yogurt topped with crunchy walnuts and a generous drizzle of honey. A simple, nutritious breakfast or light dessert.\",\"products\":[{\"productName\":\"Yogurt\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Honey\",\"position\":2,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Walnuts\",\"position\":3,\"quantity\":60.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 4, '2026-05-07 09:30:00'),
(38, 5, 2, '{\"title\":\"Lentil Soup\",\"preparationTime\":40,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add lentils, canned tomatoes, cumin, paprika.\\\"},{\\\"text\\\":\\\"Cover with water.\\\"},{\\\"text\\\":\\\"Simmer 25 min until lentils are soft.\\\"},{\\\"text\\\":\\\"Season with salt.\\\"}]\",\"notes\":null,\"description\":\"A thick and earthy soup of red lentils, tomatoes, and aromatic cumin and paprika. Filling, budget-friendly, and naturally vegan.\",\"products\":[{\"productName\":\"Lentils\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Canned tomatoes\",\"position\":4,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Paprika\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-06-05 16:00:00'),
(39, 5, 2, '{\"title\":\"Lentil Soup\",\"preparationTime\":40,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add lentils, canned tomatoes, cumin, paprika.\\\"},{\\\"text\\\":\\\"Cover with water.\\\"},{\\\"text\\\":\\\"Simmer 25 min until lentils are soft.\\\"},{\\\"text\\\":\\\"Season with salt.\\\"}]\",\"notes\":null,\"description\":\"A thick and earthy soup of red lentils, tomatoes, and aromatic cumin and paprika. Filling, budget-friendly, and naturally vegan.\",\"products\":[{\"productName\":\"Lentils\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Canned tomatoes\",\"position\":4,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Paprika\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', 'The recipe is missing cooking notes. Please add guidance on whether to soak the lentils beforehand and include more detail on seasoning at the end.', 2, '2026-06-06 09:30:00'),
(40, 5, 5, '{\"title\":\"Lentil Soup\",\"preparationTime\":40,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add lentils, canned tomatoes, cumin, paprika.\\\"},{\\\"text\\\":\\\"Cover with water.\\\"},{\\\"text\\\":\\\"Simmer 25 min until lentils are soft.\\\"},{\\\"text\\\":\\\"Taste and adjust seasoning, then serve.\\\"}]\",\"notes\":\"No need to soak red lentils - they cook quickly. Rinse them well before using. Adjust salt at the end as canned tomatoes vary in saltiness.\",\"description\":\"A thick and earthy soup of red lentils, tomatoes, and aromatic cumin and paprika. Filling, budget-friendly, and naturally vegan.\",\"products\":[{\"productName\":\"Lentils\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Canned tomatoes\",\"position\":4,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Paprika\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-06-08 14:15:00'),
(41, 5, 5, '{\"title\":\"Lentil Soup\",\"preparationTime\":40,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add lentils, canned tomatoes, cumin, paprika.\\\"},{\\\"text\\\":\\\"Cover with water.\\\"},{\\\"text\\\":\\\"Simmer 25 min until lentils are soft.\\\"},{\\\"text\\\":\\\"Taste and adjust seasoning, then serve.\\\"}]\",\"notes\":\"No need to soak red lentils - they cook quickly. Rinse them well before using. Adjust salt at the end as canned tomatoes vary in saltiness.\",\"description\":\"A thick and earthy soup of red lentils, tomatoes, and aromatic cumin and paprika. Filling, budget-friendly, and naturally vegan.\",\"products\":[{\"productName\":\"Lentils\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Canned tomatoes\",\"position\":4,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cumin\",\"position\":5,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Paprika\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Soups & Stews\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-06-09 10:45:00'),
(42, 13, 5, '{\"title\":\"Mushroom Risotto\",\"preparationTime\":40,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion and garlic in butter.\\\"},{\\\"text\\\":\\\"Add mushrooms and cook until soft.\\\"},{\\\"text\\\":\\\"Add rice and stir 1 min.\\\"},{\\\"text\\\":\\\"Deglaze with wine.\\\"},{\\\"text\\\":\\\"Add broth one ladle at a time, stirring until absorbed before adding more.\\\"},{\\\"text\\\":\\\"Finish with grated cheese and season.\\\"}]\",\"notes\":\"Keep the broth warm in a separate pot while cooking - adding cold broth stops the cooking process and results in uneven texture. Stir constantly during the final 10 minutes.\",\"description\":\"Creamy Arborio-style rice slowly cooked with mushrooms, white wine, and chicken broth, finished with grated kashkaval. Rich and deeply savory.\",\"products\":[{\"productName\":\"Rice\",\"position\":1,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Mushrooms\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Chicken broth\",\"position\":3,\"quantity\":1000.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"White wine (for cooking)\",\"position\":4,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":7,\"quantity\":50.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":8,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":9,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":10,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-04-05 17:30:00'),
