},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-04-09 09:30:00'),
(46, 11, 5, '{\"title\":\"Baked Salmon with Dill\",\"preparationTime\":20,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Place salmon on baking sheet.\\\"},{\\\"text\\\":\\\"Rub with olive oil and minced garlic.\\\"},{\\\"text\\\":\\\"Season with salt and pepper, squeeze lemon over.\\\"},{\\\"text\\\":\\\"Bake 15 min.\\\"},{\\\"text\\\":\\\"Garnish with fresh dill.\\\"}]\",\"notes\":null,\"description\":\"Oven-roasted salmon fillet seasoned with garlic, olive oil, and fresh dill with a squeeze of lemon. Light, healthy, and ready in under 20 minutes.\",\"products\":[{\"productName\":\"Salmon (fillet)\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Lemons\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh dill\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Seafood\"}]}', NULL, 1, '2026-05-20 17:15:00'),
(47, 11, 5, '{\"title\":\"Baked Salmon with Dill\",\"preparationTime\":20,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Place salmon on baking sheet.\\\"},{\\\"text\\\":\\\"Rub with olive oil and minced garlic.\\\"},{\\\"text\\\":\\\"Season with salt and pepper, squeeze lemon over.\\\"},{\\\"text\\\":\\\"Bake 15 min.\\\"},{\\\"text\\\":\\\"Garnish with fresh dill.\\\"}]\",\"notes\":null,\"description\":\"Oven-roasted salmon fillet seasoned with garlic, olive oil, and fresh dill with a squeeze of lemon. Light, healthy, and ready in under 20 minutes.\",\"products\":[{\"productName\":\"Salmon (fillet)\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Lemons\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh dill\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Seafood\"}]}', 'Please specify the oven rack position for more even cooking. Also consider adding a brief resting time before serving so the fish finishes cooking from residual heat.', 2, '2026-05-21 14:30:00'),
(48, 11, 2, '{\"title\":\"Baked Salmon with Dill\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Place salmon on a lined baking sheet.\\\"},{\\\"text\\\":\\\"Rub with olive oil and minced garlic.\\\"},{\\\"text\\\":\\\"Season with salt and pepper, squeeze lemon over.\\\"},{\\\"text\\\":\\\"Bake 15 min on the middle rack.\\\"},{\\\"text\\\":\\\"Rest 3 min, then garnish with fresh dill and serve.\\\"}]\",\"notes\":\"Place salmon on the middle oven rack for even cooking. Let it rest 3 minutes before serving - the fish continues cooking from residual heat and will flake perfectly.\",\"description\":\"Oven-roasted salmon fillet seasoned with garlic, olive oil, and fresh dill with a squeeze of lemon. Light, healthy, and ready in under 25 minutes.\",\"products\":[{\"productName\":\"Salmon (fillet)\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Lemons\",\"position\":2,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh dill\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Seafood\"}]}', NULL, 1, '2026-05-23 09:20:00'),
