(50, 26, 2, '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":30,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min until thickened.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Season and use on pasta or as dipping sauce.\\\"}]\",\"notes\":null,\"description\":\"A chunky tomato and pepper sauce with garlic and oregano, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-06-17 16:30:00'),
(51, 26, 2, '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":30,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min until thickened.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Season and use on pasta or as dipping sauce.\\\"}]\",\"notes\":null,\"description\":\"A chunky tomato and pepper sauce with garlic and oregano, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', 'The recipe needs clearer guidance on sauce thickness and when to stop simmering. Please add notes about desired consistency and a tip for blending.', 2, '2026-06-18 09:45:00'),
(52, 26, 5, '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":30,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Season to taste and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"notes\":\"The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.\",\"description\":\"A chunky tomato and pepper sauce with garlic and oregano, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 1, '2026-06-20 14:00:00'),
(53, 26, 5, '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":30,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Season to taste and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"notes\":\"The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.\",\"description\":\"A chunky tomato and pepper sauce with garlic and oregano, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', NULL, 4, '2026-06-21 10:15:00'),
(54, 27, 5, '{\"title\":\"Bacon and Egg Potato Hash\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Dice potatoes and parboil 10 min.\\\"},{\\\"text\\\":\\\"Fry Bakone in pan until crispy, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in remaining fat, add oil if needed.\\\"},{\\\"text\\\":\\\"Add potatoes and fry until golden.\\\"},{\\\"text\\\":\\\"Make 4 wells and crack in eggs.\\\"},{\\\"text\\\":\\\"Cover and cook until eggs set.\\\"},{\\\"text\\\":\\\"Top with Bakone and parsley.\\\"}]\",\"notes\":null,\"description\":\"Crispy diced potatoes fried with Bakone and topped with eggs cooked right in the pan. A satisfying, all-in-one breakfast skillet.\",\"products\":[{\"productName\":\"Potatoes\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Bakone\",\"position\":2,\"quantity\":150.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Sunflower oil\",\"position\":6,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 1, '2026-06-09 16:00:00'),
(55, 27, 5, '{\"title\":\"Bacon and Egg Potato Hash\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Dice potatoes and parboil 10 min.\\\"},{\\\"text\\\":\\\"Fry Bakone in pan until crispy, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in remaining fat, add oil if needed.\\\"},{\\\"text\\\":\\\"Add potatoes and fry until golden.\\\"},{\\\"text\\\":\\\"Make 4 wells and crack in eggs.\\\"},{\\\"text\\\":\\\"Cover and cook until eggs set.\\\"},{\\\"text\\\":\\\"Top with Bakone and parsley.\\\"}]\",\"notes\":null,\"description\":\"Crispy diced potatoes fried with Bakone and topped with eggs cooked right in the pan. A satisfying, all-in-one breakfast skillet.\",\"products\":[{\"productName\":\"Potatoes\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Bakone\",\"position\":2,\"quantity\":150.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Sunflower oil\",\"position\":6,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', 'The egg cooking step needs more specific guidance on heat level and timing. Please add a visual cue so cooks know when the eggs are properly set without over-cooking.', 2, '2026-06-10 09:45:00'),
(56, 27, 2, '{\"title\":\"Bacon and Egg Potato Hash\",\"preparationTime\":30,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Dice potatoes and parboil 10 min, then drain and pat dry.\\\"},{\\\"text\\\":\\\"Fry Bakone in pan until crispy, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in remaining fat, add oil if needed.\\\"},{\\\"text\\\":\\\"Add potatoes and fry over medium-high heat until golden and crispy, about 8 min.\\\"},{\\\"text\\\":\\\"Reduce to medium-low, make 4 wells and crack in eggs.\\\"},{\\\"text\\\":\\\"Cover and cook 3-4 min until whites are fully set but yolks are still runny.\\\"},{\\\"text\\\":\\\"Top with Bakone and parsley and serve immediately.\\\"}]\",\"notes\":null,\"description\":\"Crispy diced potatoes fried with Bakone and topped with eggs cooked right in the pan. A satisfying, all-in-one breakfast skillet.\",\"products\":[{\"productName\":\"Potatoes\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Bakone\",\"position\":2,\"quantity\":150.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Sunflower oil\",\"position\":6,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"}]}', NULL, 1, '2026-06-12 14:30:00'),
