(1, 2, 3, '{\"servings\":4}', '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":5,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown.\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', '2026-06-19 11:00:00'),
