(3, 2, 3, '{\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\"}', '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":50,\"servings\":5,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown.\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste.\\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For best results simmer the sauce for the full 50 minutes - the longer it cooks, the richer the flavor. Deglaze with a splash of red wine after browning the beef for extra depth.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', '2026-06-19 16:45:00'),
(4, 5, 4, '{\"servings\":6}', '{\"title\":\"Chicken Soup\",\"preparationTime\":60,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Place chicken and vegetables in pot with broth.\\\"},{\\\"text\\\":\\\"Bring to boil, skim foam.\\\"},{\\\"text\\\":\\\"Simmer 40 min.\\\"},{\\\"text\\\":\\\"Remove chicken, shred meat, discard bones.\\\"},{\\\"text\\\":\\\"Return meat to soup, season and garnish with parsley.\\\"}]\",\"notes\":null,\"description\":\"A warming, golden broth with tender shredded chicken, carrots, and fresh parsley. Simple, nourishing, and perfect for any season.\",\"products\":[{\"productName\":\"Chicken leg\",\"position\":1,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Carrots\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":4,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Chicken broth\",\"position\":5,\"quantity\":1500.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":8,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Poultry\"},{\"category\":\"Soups & Stews\"}]}', '2026-06-22 10:00:00'),
