(6, 2, 7, '{\"preparationTime\":15,\"description\":\"Juicy shrimp pan-fried in fragrant garlic butter and finished with a squeeze of lemon. Ready in 15 minutes and impressive enough to serve as a starter.\"}', '{\"title\":\"Garlic Butter Shrimp\",\"preparationTime\":20,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Melt butter in pan over medium heat.\\\"},{\\\"text\\\":\\\"Add garlic and cook 1 min.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 2 min per side.\\\"},{\\\"text\\\":\\\"Squeeze lemon juice and toss with fresh parsley.\\\"}]\",\"notes\":\"Do not overcook the shrimp - they turn rubbery quickly. Pull them off the heat the moment they turn pink and curl into a C-shape.\",\"description\":\"Juicy shrimp pan-fried in fragrant garlic butter and finished with a squeeze of lemon. Ready in 20 minutes and impressive enough to serve as a starter.\",\"products\":[{\"productName\":\"Shrimp\",\"position\":1,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Butter\",\"position\":2,\"quantity\":40.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Lemons\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', '2026-06-04 14:15:00'),
