(8, 5, 9, '{\"preparationTime\":35}', '{\"title\":\"Pork Tenderloin with Mushroom Cream Sauce\",\"preparationTime\":40,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice pork and season.\\\"},{\\\"text\\\":\\\"Sear in butter until golden, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in same pan.\\\"},{\\\"text\\\":\\\"Add mushrooms, cook until soft.\\\"},{\\\"text\\\":\\\"Deglaze with wine.\\\"},{\\\"text\\\":\\\"Add cream and simmer 5 min.\\\"},{\\\"text\\\":\\\"Return pork to pan and heat through.\\\"}]\",\"notes\":\"Pat the pork completely dry before searing for a proper golden crust. Avoid crowding the pan or the meat will steam instead of brown.\",\"description\":\"Seared pork slices in a velvety cream and white wine sauce with sauteed mushrooms. An elegant dinner that feels restaurant-quality.\",\"products\":[{\"productName\":\"Pork tenderloin\",\"position\":1,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Mushrooms\",\"position\":2,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Heavy cream 35%\",\"position\":3,\"quantity\":200.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"White wine (for cooking)\",\"position\":4,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Main Dishes\"}]}', '2026-06-18 09:15:00'),
