(12, 2, 11, '{\"notes\":\"Place salmon on the middle oven rack for even cooking. Let it rest 3 minutes before serving - the fish continues cooking from residual heat and will flake perfectly.\"}', '{\"title\":\"Baked Salmon with Dill\",\"preparationTime\":25,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 200C.\\\"},{\\\"text\\\":\\\"Place salmon on a lined baking sheet.\\\"},{\\\"text\\\":\\\"Rub with olive oil and minced garlic.\\\"},{\\\"text\\\":\\\"Season with salt and pepper, squeeze lemon over.\\\"},{\\\"text\\\":\\\"Bake 15 min on the middle rack.\\\"},{\\\"text\\\":\\\"Rest 3 min, then garnish with fresh dill and serve.\\\"}]\",\"notes\":\"Middle oven rack is key for even cooking. The salmon is done when it flakes easily with a fork at the thickest part. Rest 3 minutes before serving for best texture.\",\"description\":\"Oven-roasted salmon fillet seasoned with garlic, olive oil, and fresh dill with a generous squeeze of lemon. Light, healthy, and ready in under 25 minutes.\",\"products\":[{\"productName\":\"Salmon (fillet)\",\"position\":1,\"quantity\":1200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Lemons\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh dill\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Seafood\"}]}', '2026-05-26 09:15:00'),
