(15, 2, 16, '{\"preparationTime\":25,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 180C.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in butter in an oven-safe pan.\\\"},{\\\"text\\\":\\\"Add spinach and cook until wilted.\\\"},{\\\"text\\\":\\\"Whisk eggs with salt and pepper, pour over.\\\"},{\\\"text\\\":\\\"Sprinkle grated cheese.\\\"},{\\\"text\\\":\\\"Bake 15 min until set.\\\"}]\",\"notes\":\"Make sure the spinach is fully wilted and any excess moisture is pressed out before adding the eggs, otherwise the frittata will be watery and won\'t set properly.\",\"description\":\"A baked egg dish loaded with wilted spinach and melted kashkaval cheese. A versatile, protein-rich option for breakfast or a light lunch.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":6.0,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Spinach\",\"position\":2,\"quantity\":200.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":3,\"quantity\":80.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.0,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":5,\"quantity\":2.0,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":6,\"quantity\":20.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":5.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.0,\"unitAbbreviation\":\"g\"}]}', '{\"title\":\"Spinach and Egg Frittata\",\"preparationTime\":30,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 180C.\\\"},{\\\"text\\\":\\\"Saute onion in oil until soft.\\\"},{\\\"text\\\":\\\"Add spinach and cook until wilted.\\\"},{\\\"text\\\":\\\"Whisk eggs, add salt and pepper.\\\"},{\\\"text\\\":\\\"Pour eggs over vegetables in oven-safe pan.\\\"},{\\\"text\\\":\\\"Top with grated cheese.\\\"},{\\\"text\\\":\\\"Bake 20 min until set.\\\"}]\",\"notes\":null,\"description\":\"A baked egg frittata with wilted spinach, onion, and grated kashkaval. Serve warm from the pan as a light lunch or protein-packed breakfast.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":6.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Starch\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":4,\"quantity\":50.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Sunflower oil\",\"position\":5,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":2.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Vegetarian & Vegan\"}]}', '2026-06-23 09:30:00'),
