reakfast.\",\"products\":[{\"productName\":\"Eggs\",\"position\":1,\"quantity\":8.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Starch\",\"position\":2,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":3,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Kashkaval (Yellow cheese)\",\"position\":4,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Sunflower oil\",\"position\":5,\"quantity\":20.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":6,\"quantity\":5.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":7,\"quantity\":2.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":8,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Breakfast & Brunch\"},{\"category\":\"Vegetarian & Vegan\"}]}', '2026-06-23 10:00:00'),
(17, 5, 21, '{\"servings\":8}', '{\"title\":\"Chocolate Cake\",\"preparationTime\":50,\"servings\":10,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":200.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":180.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', '2026-05-08 09:30:00'),
