(19, 5, 21, '{\"preparationTime\":50}', '{\"title\":\"Chocolate Cake\",\"preparationTime\":55,\"servings\":10,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":250.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":220.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', '2026-05-09 11:15:00'),
(20, 2, 24, '{\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Shrimp\",\"position\":2,\"quantity\":400.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.0,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":45.0,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.0,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":6,\"quantity\":1.0,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.0,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.0,\"unitAbbreviation\":\"g\"}]}', '{\"title\":\"Shrimp Pasta\",\"preparationTime\":25,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook pasta in salted water until al dente.\\\"},{\\\"text\\\":\\\"Saute garlic in olive oil until golden.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 3 min.\\\"},{\\\"text\\\":\\\"Toss with drained pasta.\\\"},{\\\"text\\\":\\\"Finish with lemon juice and chopped parsley.\\\"}]\",\"notes\":\"Reserve a cup of pasta water before draining. Adding a splash while tossing the pasta with the shrimp helps the sauce cling and keeps everything from drying out.\",\"description\":\"Spaghetti tossed with pan-fried shrimp in garlic olive oil, brightened with fresh lemon juice and parsley. A quick and elegant seafood dinner.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Shrimp\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":6.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":60.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Pasta & Noodles\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', '2026-06-14 09:30:00'),
(21, 5, 24, '{\"preparationTime\":25}', '{\"title\":\"Shrimp Pasta\",\"preparationTime\":30,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook pasta in salted water until al dente.\\\"},{\\\"text\\\":\\\"Saute garlic in olive oil until golden.\\\"},{\\\"text\\\":\\\"Add shrimp and cook 3 min.\\\"},{\\\"text\\\":\\\"Toss with drained pasta.\\\"},{\\\"text\\\":\\\"Finish with lemon juice and chopped parsley.\\\"}]\",\"notes\":\"Reserve a cup of pasta water before draining. Adding a splash while tossing the pasta with the shrimp helps the sauce cling and keeps everything from drying out.\",\"description\":\"Spaghetti tossed with pan-fried shrimp in garlic olive oil, brightened with fresh lemon juice and parsley. A quick and elegant seafood dinner.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Shrimp\",\"position\":2,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":6.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":4,\"quantity\":60.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Lemons\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Fresh parsley\",\"position\":6,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Pasta & Noodles\"},{\"category\":\"Quick & Easy (Under 30 Mins)\"},{\"category\":\"Seafood\"}]}', '2026-06-14 11:00:00'),
(22, 2, 26, '{\"preparationTime\":30,\"servings\":6,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Season to taste and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"description\":\"A chunky tomato and pepper sauce with garlic and oregano, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\"}', '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":25,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Stir in chopped parsley, season to taste, and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"notes\":\"The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.\",\"description\":\"A chunky tomato and pepper sauce with garlic, oregano, and fresh parsley, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":4.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', '2026-06-21 14:00:00'),
