ons\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', '2026-06-21 15:30:00');
