(24, 2, 26, '{\"description\":\"A chunky tomato and pepper sauce with garlic, oregano, and fresh parsley, simmered until thick and fragrant. Versatile as a pasta sauce, pizza base, or dipping sauce.\"}', '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":25,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Stir in chopped parsley, season to taste, and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"notes\":\"The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.\",\"description\":\"A chunky tomato and pepper sauce with garlic, oregano, and fresh parsley, ready in just 25 minutes. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', '2026-06-22 09:45:00');
