(1, 2, 1, '{\"title\":\"Spaghetti Bolognese\",\"preparationTime\":45,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Cook spaghetti in salted boiling water until al dente.\\\"},{\\\"text\\\":\\\"SautГ© onion and garlic in olive oil.\\\"},{\\\"text\\\":\\\"Add minced beef and brown\\\"},{\\\"text\\\":\\\"Stir in canned tomatoes and tomato paste. \\\"},{\\\"text\\\":\\\"Simmer 20 min.\\\"},{\\\"text\\\":\\\"Serve sauce over pasta.\\\"}]\",\"notes\":\"For a richer sauce, let it simmer for up to 45 minutes instead of 20. A splash of red wine added after browning the beef deepens the flavor significantly.\",\"description\":\"A rich, slow-simmered meat sauce with minced beef and canned tomatoes, served over spaghetti. A beloved Italian classic that\'s hearty and satisfying.\",\"products\":[{\"productName\":\"Spaghetti\",\"position\":1,\"quantity\":400.000,\"unitAbbreviation\":\"mg\"},{\"productName\":\"Minced beef\",\"position\":2,\"quantity\":500.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Canned tomatoes\",\"position\":3,\"quantity\":400.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Tomato paste\",\"position\":4,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":8.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Main Dishes\"},{\"category\":\"Pasta & Noodles\"}]}', 1, '2026-06-20 09:15:00'),
(2, 2, 9, '{\"title\":\"Pork Tenderloin with Mushroom Cream Sauce\",\"preparationTime\":40,\"servings\":4,\"instructions\":\"[{\\\"text\\\":\\\"Slice pork and season.\\\"},{\\\"text\\\":\\\"Sear in butter until golden, set aside.\\\"},{\\\"text\\\":\\\"Saute onion and garlic in same pan.\\\"},{\\\"text\\\":\\\"Add mushrooms, cook until soft.\\\"},{\\\"text\\\":\\\"Deglaze with wine.\\\"},{\\\"text\\\":\\\"Add cream and simmer 5 min.\\\"},{\\\"text\\\":\\\"Return pork to pan and heat through.\\\"}]\",\"notes\":\"Pat the pork completely dry before searing for a proper golden crust. Avoid crowding the pan or the meat will steam instead of brown.\",\"description\":\"Seared pork slices in a velvety cream and white wine sauce with sauteed mushrooms. An elegant dinner that feels restaurant-quality.\",\"products\":[{\"productName\":\"Pork tenderloin\",\"position\":1,\"quantity\":600.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Mushrooms\",\"position\":2,\"quantity\":300.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Heavy cream 35%\",\"position\":3,\"quantity\":250.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"White wine (for cooking)\",\"position\":4,\"quantity\":100.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Onions\",\"position\":5,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":6,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":7,\"quantity\":30.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":9,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Beef & Pork\"},{\"category\":\"Main Dishes\"}]}', 1, '2026-06-21 10:30:00'),
(3, 5, 21, '{\"title\":\"Chocolate Cake\",\"preparationTime\":55,\"servings\":10,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":250.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":220.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', 1, '2026-05-10 10:00:00'),
(4, 2, 26, '{\"title\":\"Tomato and Pepper Sauce\",\"preparationTime\":25,\"servings\":8,\"instructions\":\"[{\\\"text\\\":\\\"Saute onion, garlic, and diced peppers in oil over medium heat.\\\"},{\\\"text\\\":\\\"Add canned tomatoes and oregano.\\\"},{\\\"text\\\":\\\"Simmer 20 min, stirring occasionally, until sauce thickly coats a spoon.\\\"},{\\\"text\\\":\\\"Blend for smooth texture or leave chunky.\\\"},{\\\"text\\\":\\\"Stir in chopped parsley, season to taste, and use on pasta, pizza, or as dipping sauce.\\\"}]\",\"notes\":\"The sauce is done when it thickly coats the back of a spoon. For smooth, blend until silky. For chunky, crush tomatoes by hand before adding. Always taste and adjust salt after simmering.\",\"description\":\"A chunky tomato and pepper sauce with garlic, oregano, and fresh parsley, ready in just 25 minutes. Versatile as a pasta sauce, pizza base, or dipping sauce.\",\"products\":[{\"productName\":\"Canned tomatoes\",\"position\":1,\"quantity\":800.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Peppers\",\"position\":2,\"quantity\":2.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Garlic\",\"position\":3,\"quantity\":4.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Onions\",\"position\":4,\"quantity\":1.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Olive oil\",\"position\":5,\"quantity\":30.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Oregano\",\"position\":6,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Salt\",\"position\":7,\"quantity\":6.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Black pepper (ground)\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh parsley\",\"position\":9,\"quantity\":1.000,\"unitAbbreviation\":\"bch\"}],\"categories\":[{\"category\":\"Sauces, Dips & Dressings\"},{\"category\":\"Vegetarian & Vegan\"}]}', 1, '2026-06-23 09:30:00'),
(5, 5, 21, '{\"title\":\"Chocolate Cake\",\"preparationTime\":55,\"servings\":10,\"instructions\":\"[{\\\"text\\\":\\\"Preheat oven to 175C.\\\"},{\\\"text\\\":\\\"Cream butter and sugar until fluffy.\\\"},{\\\"text\\\":\\\"Beat in eggs and vanilla.\\\"},{\\\"text\\\":\\\"Mix in flour, cocoa, and salt alternating with milk.\\\"},{\\\"text\\\":\\\"Pour into greased pan.\\\"},{\\\"text\\\":\\\"Bake 35 min until skewer comes out clean.\\\"}]\",\"notes\":\"Do not overbake - check with a skewer at 30 minutes. The cake continues cooking from residual heat after it comes out of the oven.\",\"description\":\"A moist, dense cake with deep cocoa flavor, made with butter, eggs, and a hint of vanilla. A reliable crowd-pleasing dessert for any occasion.\",\"products\":[{\"productName\":\"Flour type 500\",\"position\":1,\"quantity\":250.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Cocoa powder\",\"position\":2,\"quantity\":60.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"White sugar\",\"position\":3,\"quantity\":220.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Eggs\",\"position\":4,\"quantity\":3.000,\"unitAbbreviation\":\"pcs\"},{\"productName\":\"Butter\",\"position\":5,\"quantity\":120.000,\"unitAbbreviation\":\"g\"},{\"productName\":\"Fresh milk\",\"position\":6,\"quantity\":150.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Vanilla (extract)\",\"position\":7,\"quantity\":5.000,\"unitAbbreviation\":\"ml\"},{\"productName\":\"Salt\",\"position\":8,\"quantity\":3.000,\"unitAbbreviation\":\"g\"}],\"categories\":[{\"category\":\"Breads & Baking\"},{\"category\":\"Desserts\"}]}', 2, '2026-05-12 14:30:00');
